Trigger.TriggerText:
-- see legacy/triggers/CUSTOMERS-WVI-CONTACT_EMAIL.plsql
DECLARE
  v_email VARCHAR2(120) := :CUSTOMERS.CONTACT_EMAIL;
BEGIN
  IF v_email IS NULL
     OR INSTR(v_email, '@') = 0
     OR INSTR(v_email, '.', INSTR(v_email, '@')) = 0 THEN
    FND_MESSAGE.SET_STRING('Contact email must be a valid email address');
    FND_MESSAGE.ERROR;
    RAISE FORM_TRIGGER_FAILURE;
  END IF;
END;

-- see legacy/triggers/SUBSCRIPTIONS-WVI-SEATS.plsql
DECLARE
  v_max_seats NUMBER;
BEGIN
  SELECT MAX_SEATS INTO v_max_seats
    FROM STORAGE_PLANS WHERE PLAN_CODE = :SUBSCRIPTIONS.PLAN_CODE;
  IF :SUBSCRIPTIONS.SEATS IS NULL OR :SUBSCRIPTIONS.SEATS < 1 THEN
    FND_MESSAGE.SET_STRING('Seats must be at least 1');
    FND_MESSAGE.ERROR; RAISE FORM_TRIGGER_FAILURE;
  END IF;
  IF :SUBSCRIPTIONS.SEATS > v_max_seats THEN
    FND_MESSAGE.SET_STRING('Seats exceed plan maximum');
    FND_MESSAGE.ERROR; RAISE FORM_TRIGGER_FAILURE;
  END IF;
END;

-- see legacy/triggers/SUBSCRIPTIONS-WVI-DISCOUNT_PCT.plsql
DECLARE
  v_max_discount NUMBER;
BEGIN
  SELECT MAX_DISCOUNT_PCT INTO v_max_discount
    FROM STORAGE_PLANS WHERE PLAN_CODE = :SUBSCRIPTIONS.PLAN_CODE;
  IF NVL(:SUBSCRIPTIONS.DISCOUNT_PCT, 0) > v_max_discount THEN
    FND_MESSAGE.SET_STRING('Discount exceeds plan maximum');
    FND_MESSAGE.ERROR; RAISE FORM_TRIGGER_FAILURE;
  END IF;
END;

-- see legacy/triggers/SUBSCRIPTIONS-WVR.plsql
BEGIN
  IF :SUBSCRIPTIONS.END_DATE IS NOT NULL
     AND :SUBSCRIPTIONS.END_DATE <= :SUBSCRIPTIONS.START_DATE THEN
    FND_MESSAGE.SET_STRING('End date must be after start date');
    FND_MESSAGE.ERROR; RAISE FORM_TRIGGER_FAILURE;
  END IF;
END;

-- see legacy/triggers/SUBSCRIPTIONS-PRE-INSERT.plsql
DECLARE
  v_cust_status VARCHAR2(10);
BEGIN
  SELECT STATUS INTO v_cust_status
    FROM BILLING_CUSTOMERS WHERE CUSTOMER_ID = :SUBSCRIPTIONS.CUSTOMER_ID;
  IF v_cust_status = 'CLOSED' THEN
    FND_MESSAGE.SET_STRING('Cannot add subscription for a closed customer');
    FND_MESSAGE.ERROR; RAISE FORM_TRIGGER_FAILURE;
  END IF;
END;
